import{_ as o,o as t,c as i,ae as n}from"./chunks/framework.B6gjLfeO.js";const h=JSON.parse('{"title":"Configure SSO With Google","description":"","frontmatter":{"title":"Configure SSO With Google","slug":"configure-sso-with-google"},"headers":[],"relativePath":"account-hub/configure-sso-with-google.md","filePath":"account-hub/configure-sso-with-google.md"}'),a={name:"account-hub/configure-sso-with-google.md"};function r(l,e,s,c,g,d){return t(),i("div",null,[...e[0]||(e[0]=[n('<h2 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h2><p>This guide provides step-by-step instructions for setting up Single Sign-On (SSO) with Branch using <strong>Google</strong> as your Identity Provider (IdP).</p><p>This guide will:</p><ol><li>Help you get your configuration details from Branch.</li><li>Show you how to create and configure a SAML 2.0 application in Google Workspace.</li><li>Link you back to the main <a href="./configure-sso.html">Configure SSO guide</a> to complete the setup.</li></ol><h2 id="configure-sso" tabindex="-1">Configure SSO <a class="header-anchor" href="#configure-sso" aria-label="Permalink to &quot;Configure SSO&quot;">​</a></h2><p>To configure SSO, you’ll need to get your unique URLs from Branch, configure Google, and then finish the setup in Branch.</p><h3 id="before-you-begin" tabindex="-1">Before you begin <a class="header-anchor" href="#before-you-begin" aria-label="Permalink to &quot;Before you begin&quot;">​</a></h3><p>Before you begin, ensure you have:</p><ul><li><p>Admin access to your Branch account.</p></li><li><p>Admin access to the Google Admin console.</p></li><li><p>SSO enabled for your Branch account.</p><ul><li>Access to SSO requires a Branch plan. Please visit our <a href="https://www.branch.io/pricing/" target="_blank" rel="noreferrer">Pricing</a> page or <a href="https://branchdocs.app.link/e/sso-sign-up" target="_blank" rel="noreferrer">contact our Sales team</a> to learn more about pricing and availability.</li></ul></li></ul><h3 id="step-1-get-configuration-details-from-branch" tabindex="-1">Step 1: Get configuration details from Branch <a class="header-anchor" href="#step-1-get-configuration-details-from-branch" aria-label="Permalink to &quot;Step 1: Get configuration details from Branch&quot;">​</a></h3><p>This step is different depending on whether you are on the <a href="./branch-dashboard-overview.html">legacy</a> or <a href="./new-branch-overview.html">new</a> Branch experience. The rest of the steps remain the same between the two platforms.</p><h3 id="step-2-configure-google-saml" tabindex="-1">Step 2: Configure Google SAML <a class="header-anchor" href="#step-2-configure-google-saml" aria-label="Permalink to &quot;Step 2: Configure Google SAML&quot;">​</a></h3><p>In a different tab, log in to your Google Admin console to create the Branch application.</p><ol><li>In Google Admin, navigate to <strong>Apps</strong> → <strong>Web and mobile apps</strong>.</li><li>Select <strong>Add app</strong> → <strong>Add custom SAML app</strong>.</li><li>On the App details page, enter an app name (e.g., &quot;Branch&quot;) and optionally add a description or upload an app icon. Select <strong>Continue</strong>.</li></ol><h3 id="step-3-download-google-idp-details" tabindex="-1">Step 3: Download Google IdP details <a class="header-anchor" href="#step-3-download-google-idp-details" aria-label="Permalink to &quot;Step 3: Download Google IdP details&quot;">​</a></h3><p>On the <strong>Google Identity Provider details</strong> page in Google Admin, there is configuration information that you&#39;ll need for Branch.</p><p>Keep this page open - you&#39;ll need to copy the <strong>SSO URL</strong> and download the <strong>Certificate</strong> in the next step.</p><h3 id="step-4-configure-connection-in-branch" tabindex="-1">Step 4: Configure connection in Branch <a class="header-anchor" href="#step-4-configure-connection-in-branch" aria-label="Permalink to &quot;Step 4: Configure connection in Branch&quot;">​</a></h3><p>Before completing the Google configuration, you need to provide Google&#39;s IdP details to Branch.</p><ol><li>Go back to your Branch <strong>Configure Custom SAML</strong> browser tab (from Step 1).</li><li>On the <strong>Configure connection</strong> page, select <strong>Manual</strong>.</li><li>Copy the <strong>SSO URL</strong> from Google (from Step 3) and paste it into Branch&#39;s <strong>Single Sign-On Login URL</strong> field.</li><li>Select <strong>Download Certificate</strong> in Google&#39;s setup page to download the certificate file.</li><li>Upload this certificate file to Branch&#39;s <strong>Signing Certificate</strong> field.</li><li>Keep the Branch tab open - you&#39;ll complete the connection after finishing the Google setup.</li></ol><h3 id="step-5-configure-service-provider-details-in-google" tabindex="-1">Step 5: Configure service provider details in Google <a class="header-anchor" href="#step-5-configure-service-provider-details-in-google" aria-label="Permalink to &quot;Step 5: Configure service provider details in Google&quot;">​</a></h3><p>Return to the Google Admin console to complete the SAML app configuration.</p><ol><li><p>On the <strong>Service provider details</strong> page, fill in the fields using the values from the Branch tab you kept open from Step 1:</p><ol><li>ACS URL: Paste the <strong>Single Sign-On URL</strong> from Branch.</li><li>Entity ID: Paste the <strong>Service Provider Entity ID</strong> from Branch.</li><li>Start URL (optional): Leave blank.</li><li>Signed response: Leave unchecked.</li></ol></li><li><p>Configure the <strong>Name ID</strong> settings:</p><ol><li>Name ID format: Set to <strong>UNSPECIFIED</strong></li><li>Name ID: Set to <strong>Basic Information &gt; Primary email</strong></li></ol></li><li><p>Select <strong>Continue</strong>.</p></li></ol><h3 id="step-6-map-attributes-in-google" tabindex="-1">Step 6: Map attributes in Google <a class="header-anchor" href="#step-6-map-attributes-in-google" aria-label="Permalink to &quot;Step 6: Map attributes in Google&quot;">​</a></h3><p>Branch requires three attributes to be sent in the SAML response to provision and identify users.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>To set up a successful mapping, you must use the attribute names <code>firstName</code>, <code>lastName</code>, and <code>email</code> exactly as they are capitalized and spelled here. Do not use URN or OID formats.</p></div><table tabindex="0"><thead><tr><th><strong>Google Directory attributes</strong></th><th><strong>App attributes</strong></th></tr></thead><tbody><tr><td>Primary email</td><td><code>email</code></td></tr><tr><td>First name</td><td><code>firstName</code></td></tr><tr><td>Last name</td><td><code>lastName</code></td></tr></tbody></table><ol><li>On Google’s Attribute mapping page, use <strong>Add mapping</strong> to add each attribute from the table above.</li><li>Make sure you enter the app attribute names exactly as spelled and cased here: <code>email</code>, <code>firstName</code>, <code>lastName</code></li><li>Select <strong>Finish</strong> to save your Google Workspace application.</li></ol><h3 id="step-7-test-sso" tabindex="-1">Step 7: Test SSO <a class="header-anchor" href="#step-7-test-sso" aria-label="Permalink to &quot;Step 7: Test SSO&quot;">​</a></h3><p>Use <a href="./configure-sso.html#step-24-test-sso">step 2.4</a> from our main SSO guide to test the connection between Google and Branch.</p><h2 id="more-information" tabindex="-1">More information <a class="header-anchor" href="#more-information" aria-label="Permalink to &quot;More information&quot;">​</a></h2><p>For more complete information about configuring SSO for Branch, visit our <a href="./configure-sso.html">Configure SSO (General SAML) guide</a>.</p>',32)])])}const u=o(a,[["render",r]]);export{h as __pageData,u as default};
